// LEVER 1: DEMAND SENSING
// Replicates McKinsey Supply Chain 4.0, Lever 1
// McKinsey benchmark: 20-50% forecast error reduction

const trends = $input.first().json;
const inventory = $('Fetch: Warehouse Inventory (Supply Signal)').first().json;

// Parse trend data (SerpAPI format)
const trendData = trends.interest_over_time?.timeline_data || [];
const latestTrend = trendData[trendData.length - 1]?.values?.[0]?.value || 0;

// Calibration: Google Trends index → units/day
// Key insight from McKinsey: you CANNOT use raw index as units.
// Must calibrate with historical sales data.
const CALIBRATION_FACTOR = 0.85; // units/day per 1.0 index (Delhi NCR example)
const TREND_MULTIPLIER = latestTrend > 70 ? 1.25 : 1.0; // Mamaearth heuristic

const forecastUnitsPerDay = CALIBRATION_FACTOR * latestTrend * TREND_MULTIPLIER;
const currentInventoryDays = 30; // from company data
const targetInventoryDays = 15;  // McKinsey + our target

// McKinsey Lever 1 output
const lever1 = {
  lever: 'L1_DEMAND_SENSING',
  trend_index: latestTrend,
  is_spiking: latestTrend > 70,
  forecast_units_per_day: Math.round(forecastUnitsPerDay * 10) / 10,
  current_inv_days: currentInventoryDays,
  target_inv_days: targetInventoryDays,
  impact_cr: Math.round((currentInventoryDays - targetInventoryDays) * forecastUnitsPerDay * 349 * 0.25 / 365 / 100000) / 100,
  confidence: latestTrend > 60 ? 'HIGH' : 'MEDIUM',
  mckinsey_gap: 'McKinsey uses POS data. We use Google Trends (normalized, not units)',
  timestamp: new Date().toISOString(),
};

return [{ json: lever1 }];

// LEVER 3: INVENTORY OPTIMISATION
// Replicates McKinsey Supply Chain 4.0, Lever 3
// McKinsey benchmark: 20-30% inventory reduction

const inventoryData = $('Fetch: Warehouse Inventory (Supply Signal)').first().json;
const demand = $('Code: Lever 1 — Demand Sensing').first().json;

// Parse inventory rows from Google Sheets
const rows = inventoryData.values || [];
const headers = rows[0] || [];

const warehouses = rows.slice(1).map(row => {
  const obj = {};
  headers.forEach((h, i) => obj[h] = row[i]);
  return obj;
});

// Compute states for each warehouse (from agent.py logic)
const TARGET_DAYS = 15;
const SAFETY_DAYS = 2;

const states = warehouses.map(wh => {
  const available = parseInt(wh.on_hand_units || 0) - parseInt(wh.blocked_units || 0);
  // Demand per day: would come from Lever 1 in production
  // Here: use a simplified proxy (trend index × calibration)
  const demandPerDay = demand.forecast_units_per_day * 0.3; // 30% of total goes to each warehouse roughly
  const daysCover = available / Math.max(0.001, demandPerDay);
  const targetUnits = (TARGET_DAYS + SAFETY_DAYS) * demandPerDay;
  const excess = Math.max(0, available - targetUnits);
  const deficit = Math.max(0, targetUnits - available);

  return {
    warehouse_id: wh.warehouse_id,
    city: wh.city,
    available_units: available,
    days_cover: Math.round(daysCover * 10) / 10,
    excess_units: Math.round(excess),
    deficit_units: Math.round(deficit),
    status: daysCover < 5 ? 'CRITICAL' : excess > 0 ? 'DONOR' : deficit > 0 ? 'RECEIVER' : 'HEALTHY',
  };
});

// Simple transfer recommendation (greedy matching)
const donors = states.filter(s => s.status === 'DONOR').sort((a, b) => b.excess_units - a.excess_units);
const receivers = states.filter(s => s.status === 'CRITICAL' || s.status === 'RECEIVER')
  .sort((a, b) => b.deficit_units - a.deficit_units);

const transfers = [];
donors.forEach(donor => {
  receivers.forEach(receiver => {
    if (donor.excess_units > 0 && receiver.deficit_units > 0) {
      const ship = Math.min(donor.excess_units, receiver.deficit_units, 500);
      if (ship >= 50) {
        transfers.push({
          from: donor.city,
          to: receiver.city,
          units: Math.round(ship / 50) * 50, // MOQ 50
          priority: receiver.status === 'CRITICAL' ? 'CRITICAL' : 'HIGH',
          carrying_cost_avoided_rs: Math.round(ship * 349 * 0.25 / 365 * 7),
          transfer_cost_rs: ship * 12,
        });
        donor.excess_units -= ship;
        receiver.deficit_units -= ship;
      }
    }
  });
});

const lever3 = {
  lever: 'L3_INVENTORY_OPTIMISATION',
  warehouse_states: states,
  transfers_recommended: transfers,
  total_units_moving: transfers.reduce((s, t) => s + t.units, 0),
  critical_warehouses: states.filter(s => s.status === 'CRITICAL').length,
  mckinsey_gap: 'McKinsey uses OR-Tools min-cost flow. We use greedy heuristic (~5-10% sub-optimal)',
  timestamp: new Date().toISOString(),
};

return [{ json: lever3 }];

// COMBINE all levers into one Slack-ready message
const lever1 = $('Code: Lever 1 — Demand Sensing').first().json;
const lever3 = $('Code: Lever 3 — Inventory Optimisation').first().json;

const critical = lever3.warehouse_states?.filter(s => s.status === 'CRITICAL') || [];
const transfers = lever3.transfers_recommended || [];
const totalUnits = lever3.total_units_moving || 0;

let message = `*🤖 McKINSEY SUPPLY CHAIN AGENT — Daily Run*\n`;
message += `Date: ${new Date().toLocaleDateString('en-IN')}\n\n`;

// Demand signal
message += `*DEMAND SIGNAL (Lever 1)*\n`;
message += `Trend Index: ${lever1.trend_index}/100 ${lever1.is_spiking ? '📈 SPIKING' : '→ STABLE'}\n`;
message += `Forecast: ${lever1.forecast_units_per_day} units/day\n\n`;

// Inventory status
message += `*WAREHOUSE STATUS (Lever 3)*\n`;
if (critical.length > 0) {
  message += `🔴 CRITICAL: ${critical.map(c => c.city).join(', ')}\n`;
}
if (transfers.length > 0) {
  message += `\n*TRANSFER RECOMMENDATIONS:*\n`;
  transfers.forEach((t, i) => {
    message += `[${i+1}] ${t.priority}: ${t.from} → ${t.to} | ${t.units} units\n`;
    message += `    Carrying cost avoided: ₹${t.carrying_cost_avoided_rs.toLocaleString()}\n`;
  });
  message += `\n*TOTAL: ${totalUnits} units moving*\n`;
  message += `\n_Reply APPROVE to execute transfers or SKIP to ignore_`;
} else {
  message += `✅ All warehouses within target. No transfers needed.\n`;
}

message += `\n\n_McKinsey Supply Chain 4.0 Replication | Ridhi Jain | github.com/ridhijain709_`;

return [{ json: { message, lever1, lever3 } }];
